Trigger.TriggerText:
BEGIN
    -- Session validation
    IF NOT PKG_SECURITY.is_session_valid(
        TO_NUMBER(GET_APPLICATION_PROPERTY(USERNAME))) THEN
        MESSAGE('Session expired.');
        RAISE FORM_TRIGGER_FAILURE;
    END IF;

    SET_WINDOW_PROPERTY(FORMS_MDI_WINDOW, TITLE,
        'HRMS - Leave Management [' || :GLOBAL.current_user || ']');

    -- Show current user's leave requests by default
    SET_BLOCK_PROPERTY('LEAVE_REQUEST', DEFAULT_WHERE,
        'EMP_ID = ' || :GLOBAL.current_emp_id || ' ORDER BY CREATED_DATE DESC');

    -- Populate leave type LOV
    POPULATE_GROUP('RG_LEAVE_TYPES');

    GO_BLOCK('LEAVE_REQUEST');
    EXECUTE_QUERY;

    -- Show leave balances
    GO_BLOCK('LEAVE_BALANCE');
    EXECUTE_QUERY;
    GO_BLOCK('LEAVE_REQUEST');
END;

BEGIN
    IF :LEAVE_REQUEST.STATUS NOT IN ('PENDING', 'APPROVED') THEN
        MESSAGE('Only pending or approved requests can be cancelled.');
        RAISE FORM_TRIGGER_FAILURE;
    END IF;

    IF SHOW_ALERT('ALT_CONFIRM_CANCEL') = ALERT_BUTTON1 THEN
        PKG_LEAVE.cancel_leave_request(
            :LEAVE_REQUEST.REQUEST_ID, 'Cancelled by employee', :GLOBAL.current_user);
        MESSAGE('Leave request cancelled.');
        EXECUTE_QUERY;
    END IF;
END;

BEGIN
    SELECT lt.LEAVE_TYPE_NAME INTO :LEAVE_REQUEST.LEAVE_TYPE_NAME_DISP
    FROM LEAVE_TYPES lt
    JOIN LEAVE_REQUESTS lr ON lt.LEAVE_TYPE_ID = lr.LEAVE_TYPE_ID
    WHERE lr.REQUEST_ID = :LEAVE_REQUEST.REQUEST_ID;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        :LEAVE_REQUEST.LEAVE_TYPE_NAME_DISP := 'Unknown';
END;

DECLARE
    v_request_id NUMBER;
BEGIN
    -- Validate required fields
    IF :NEW_REQUEST.NR_LEAVE_TYPE_ID IS NULL THEN
        MESSAGE('Please select a leave type.');
        RAISE FORM_TRIGGER_FAILURE;
    END IF;
    IF :NEW_REQUEST.NR_START_DATE IS NULL THEN
        MESSAGE('Please enter a start date.');
        RAISE FORM_TRIGGER_FAILURE;
    END IF;
    IF :NEW_REQUEST.NR_END_DATE IS NULL THEN
        MESSAGE('Please enter an end date.');
        RAISE FORM_TRIGGER_FAILURE;
    END IF;

    v_request_id := PKG_LEAVE.submit_leave_request(
        p_emp_id        => :GLOBAL.current_emp_id,
        p_leave_type_id => :NEW_REQUEST.NR_LEAVE_TYPE_ID,
        p_start_date    => :NEW_REQUEST.NR_START_DATE,
        p_end_date      => :NEW_REQUEST.NR_END_DATE,
        p_half_day_flag => NVL(:NEW_REQUEST.NR_HALF_DAY, 'N'),
        p_reason        => :NEW_REQUEST.NR_REASON,
        p_user          => :GLOBAL.current_user
    );

    MESSAGE('Leave request #' || v_request_id || ' submitted successfully.');
    CLEAR_BLOCK(NO_VALIDATE);

    -- Refresh requests list
    GO_BLOCK('LEAVE_REQUEST');
    EXECUTE_QUERY;
END;
